// 提示词解析与批量请求构建（使用批量图片生成API）
// 【修复】第一张图片强制满足亚马逊主图要求
// 【增强】为每张图片的提示词添加强制产品图参考要求
// 【优化】第一张白底主图不添加无关元数据信息
// 【修复】兼容openapi.giikin.com API响应格式: {code:0, data:"内容", message:"ok"}

// ============ 配置项（方便查看修改） ============
// 【重要】n8n服务地址，用于替换callbackUrl中的host:port
const N8N_HOST = 'openapi.giikin.com';
const N8N_BASE_URL = `https://${N8N_HOST}`;

const inputItem = $input.first().json;

// ============ 获取市场配置 ============
let country = 'jp';
let requestId = '';
let modelId = 3;
let promptLang = 'en';

let inputVars = {};
try {
  inputVars = $('设置输入变量').first().json || {};
  country = inputVars.country || 'jp';
  requestId = inputVars.request_id || $execution.id;
  modelId = inputVars.model_id || 3;
  promptLang = inputVars.prompt_lang || 'en';
} catch(e) {
  requestId = $execution.id;
}

const isChinesePrompt = promptLang === 'cn';

// ============ 【新增】产品图片强制参考要求 ============
// 这是强制生图模型严格参考产品图片的关键提示词
const PRODUCT_REFERENCE_REQUIREMENTS = isChinesePrompt ? {
  prefix: '【必须严格参考提供的产品原图】产品外观、颜色、材质、形状、细节必须与参考图完全一致，',
  suffix: '，【绝对红线】产品必须与参考图一模一样，不得自行想象或改变产品外观，产品是要售卖的商品必须准确还原'
} : {
  prefix: '[MUST STRICTLY REFERENCE PROVIDED PRODUCT IMAGES] Product appearance, color, material, shape, and details must be EXACTLY identical to reference images, ',
  suffix: ', [ABSOLUTE REQUIREMENT] Product must look EXACTLY like the reference images, DO NOT imagine or change product appearance, this is a real product for sale that must be accurately reproduced'
};

// ============ 亚马逊主图强制要求（第一张图片专用） ============
// 【关键】强制只展示单个产品，禁止多个产品，简洁白底主图
const AMAZON_MAIN_IMAGE_REQUIREMENTS = isChinesePrompt ? {
  prefix: '纯白色背景 RGB(255,255,255)，【强制要求】只展示单个产品，绝对禁止出现多个产品或产品组合，',
  suffix: '，产品为绝对主角居中展示，单个产品占画面85%以上，1000x1000像素以上高清画质，禁止任何配件出现，禁止水印，禁止LOGO，禁止任何文字，禁止促销信息，禁止多个商品，无变形，无失真，准确比例，专业影棚灯光，商业产品摄影'
} : {
  prefix: 'Pure white background RGB(255,255,255), [MANDATORY] ONLY ONE SINGLE PRODUCT, absolutely NO multiple products or product combinations allowed, ',
  suffix: ', product as absolute hero centered, SINGLE product occupies 85%+ of frame, 1000x1000 pixels or higher resolution, NO accessories allowed, NO watermarks, NO logos, NO text of any kind, NO promotional information, NO multiple items, no distortion, accurate proportions, professional studio lighting, commercial product photography'
};

// ============ 市场专属文字设计规范 ============
const marketTextDesign = isChinesePrompt ? {
  'jp': '使用现代日语黑体字体，文字置于底部20%横幅区域不遮挡产品，标题占图片高度10-12%加粗，副文字为标题的60%，高对比度配色红色#E60033或橙色#FF6600强调，微微投影增强可读性',
  'us': '使用简洁现代无衬线字体如Montserrat或Helvetica，文字置于底部20%横幅区域不遮挡产品，标题占图片高度10-12%加粗，副文字为标题的60%，高对比度配色亚马逊橙#FF9900强调，微微投影增强可读性',
  'uk': '使用优雅现代无衬线字体，文字置于底部20%横幅区域不遮挡产品，标题占图片高度10-12%加粗，副文字为标题的60%，高对比度深蓝色强调，微微投影增强可读性',
  'de': '使用精确几何无衬线字体如DIN，文字置于底部20%横幅区域不遮挡产品，标题占图片高度10-12%加粗，副文字为标题的60%，高对比度深蓝或绿色#2E7D32强调，微微投影增强可读性',
  'fr': '使用优雅衬线或无衬线字体如Garamond，文字置于底部20%横幅区域不遮挡产品，标题占图片高度10-12%加粗，副文字为标题的60%，高对比度酒红或金色#D4AF37强调，微微投影增强可读性',
  'es': '使用温暖现代无衬线字体，文字置于底部20%横幅区域不遮挡产品，标题占图片高度10-12%加粗，副文字为标题的60%，高对比度暖橙色强调，微微投影增强可读性',
  'it': '使用时尚展示字体如Futura，文字置于底部20%横幅区域不遮挡产品，标题占图片高度10-12%加粗，副文字为标题的60%，高对比度经典黑或金色强调，微微投影增强可读性',
  'cn': '使用现代中文无衬线字体如苹方，文字置于底部20%横幅区域不遮挡产品，标题占图片高度10-12%加粗，副文字为标题的60%，高对比度红色#E60033或金色强调，微微投影增强可读性'
} : {
  'jp': 'text using modern Japanese Gothic style font, text in bottom 20% banner area not overlapping product, headline 10-12% image height with bold weight, subtext 60% of headline size, high contrast with red #E60033 or orange #FF6600 accent, subtle drop shadow for readability',
  'us': 'text using clean modern sans-serif font like Montserrat or Helvetica, text in bottom 20% banner area not overlapping product, headline 10-12% image height with bold weight, subtext 60% of headline size, high contrast with Amazon orange #FF9900 accent, subtle drop shadow for readability',
  'uk': 'text using elegant modern sans-serif font like Gill Sans, text in bottom 20% banner area not overlapping product, headline 10-12% image height with bold weight, subtext 60% of headline size, high contrast with navy blue accent, subtle drop shadow for readability',
  'de': 'text using precise geometric sans-serif font like DIN, text in bottom 20% banner area not overlapping product, headline 10-12% image height with bold weight, subtext 60% of headline size, high contrast with dark blue or green #2E7D32 accent, subtle drop shadow for readability',
  'fr': 'text using elegant serif or refined sans-serif font like Garamond, text in bottom 20% banner area not overlapping product, headline 10-12% image height with bold weight, subtext 60% of headline size, high contrast with burgundy or gold #D4AF37 accent, subtle drop shadow for readability',
  'es': 'text using warm modern sans-serif font like Proxima Nova, text in bottom 20% banner area not overlapping product, headline 10-12% image height with bold weight, subtext 60% of headline size, high contrast with warm orange accent, subtle drop shadow for readability',
  'it': 'text using stylish sans-serif or display font like Futura, text in bottom 20% banner area not overlapping product, headline 10-12% image height with bold weight, subtext 60% of headline size, high contrast with classic black or gold accent, subtle drop shadow for readability',
  'cn': 'text using modern Chinese sans-serif font like PingFang, text in bottom 20% banner area not overlapping product, headline 10-12% image height with bold weight, subtext 60% of headline size, high contrast with red #E60033 or gold accent, subtle drop shadow for readability'
};

const textDesignPrompt = marketTextDesign[country] || marketTextDesign['us'];

// ============ 获取参考图片URL ============
let imgUrls = [];
try {
  const imgList = inputVars.product_img_url_list || [];
  if (Array.isArray(imgList)) {
    for (const img of imgList) {
      let url = '';
      if (typeof img === 'object' && img !== null) {
        url = img.url || img.remote_url || '';
      } else if (typeof img === 'string') {
        url = img;
      }
      if (url && url.startsWith('http')) {
        imgUrls.push(url);
      }
    }
  }
} catch (e) {}

// ============ 产品图片状态标记 ============
const hasProductImages = imgUrls.length > 0;

// ============ 【修复】兼容openapi.giikin.com API响应格式 ============
// 从做图提示词生成节点获取AI生成的内容
let aiGeneratedContent = '';

// 方式1：openapi.giikin.com 格式 - data直接是字符串内容
if (inputItem.data !== undefined) {
  if (typeof inputItem.data === 'string') {
    aiGeneratedContent = inputItem.data;
  } else if (inputItem.data && typeof inputItem.data === 'object') {
    if (inputItem.data.content) aiGeneratedContent = inputItem.data.content;
    else if (inputItem.data.message && typeof inputItem.data.message === 'string') aiGeneratedContent = inputItem.data.message;
  }
}

// 方式2：标准OpenAI格式 choices[0].message.content
if (!aiGeneratedContent && inputItem.choices && Array.isArray(inputItem.choices) && inputItem.choices[0]) {
  if (inputItem.choices[0].message && inputItem.choices[0].message.content) {
    aiGeneratedContent = inputItem.choices[0].message.content;
  } else if (inputItem.choices[0].content) {
    aiGeneratedContent = inputItem.choices[0].content;
  }
}

// 方式3：其他可能的格式
if (!aiGeneratedContent) {
  if (inputItem.content) aiGeneratedContent = typeof inputItem.content === 'string' ? inputItem.content : JSON.stringify(inputItem.content);
  else if (inputItem.result && typeof inputItem.result === 'string') aiGeneratedContent = inputItem.result;
  else if (inputItem.text) aiGeneratedContent = inputItem.text;
  else if (inputItem.response) aiGeneratedContent = typeof inputItem.response === 'string' ? inputItem.response : (inputItem.response.content || '');
  else if (inputItem.output) {
    if (typeof inputItem.output === 'string') aiGeneratedContent = inputItem.output;
    else if (inputItem.output.content) aiGeneratedContent = inputItem.output.content;
    else if (inputItem.output.text) aiGeneratedContent = inputItem.output.text;
  }
}

// 调试信息
const debugInfo = {
  contentLength: aiGeneratedContent.length,
  hasJsonBlock: aiGeneratedContent.includes('```json'),
  hasPromptsField: aiGeneratedContent.includes('"prompts"'),
  parseMethod: 'none',
  parseError: null,
  parsedCount: 0,
  promptLang: promptLang,
  productImageCount: imgUrls.length,
  hasProductImageReference: hasProductImages,
  inputItemKeys: Object.keys(inputItem),
  apiFormat: inputItem.data !== undefined ? 'giikin' : (inputItem.choices ? 'openai' : 'unknown')
};

const prompts = [];

// ============ 增强JSON解析函数 ============
function safeJsonParse(str) {
  if (!str || typeof str !== 'string') return null;

  try {
    return JSON.parse(str);
  } catch(e1) {
    try {
      let cleaned = str.replace(/^[\s\uFEFF\xA0]+|[\s\uFEFF\xA0]+$/g, '');
      cleaned = cleaned.replace(/^[^{\[]+/, '').replace(/[^}\]]+$/, '');
      return JSON.parse(cleaned);
    } catch(e2) {
      try {
        let fixed = str
          .replace(/,\s*}/g, '}')
          .replace(/,\s*]/g, ']')
          .replace(/([\w"'])\s*\n\s*(["'\w{\[])/g, '$1,$2');
        return JSON.parse(fixed);
      } catch(e3) {
        return null;
      }
    }
  }
}

// ============ 方法1: 提取并解析JSON块 ============
try {
  const jsonBlockMatch = aiGeneratedContent.match(/```json\s*([\s\S]*?)```/);
  if (jsonBlockMatch && jsonBlockMatch[1]) {
    const jsonStr = jsonBlockMatch[1].trim();
    debugInfo.parseMethod = 'jsonBlock';

    const parsed = safeJsonParse(jsonStr);
    if (parsed && parsed.prompts && Array.isArray(parsed.prompts)) {
      for (let i = 0; i < parsed.prompts.length && i < 8; i++) {
        const item = parsed.prompts[i];
        const promptText = item.prompt || item.text || item.content || item.description || '';
        if (promptText && promptText.length > 20) {
          prompts[i] = promptText;
        }
      }
      debugInfo.parsedCount = prompts.filter(p => p).length;
    }
  }
} catch (e) {
  debugInfo.parseError = 'jsonBlock: ' + (e.message || '');
}

// ============ 方法2: 直接匹配包含prompts的JSON对象 ============
if (prompts.filter(p => p).length < 4) {
  try {
    const jsonObjMatch = aiGeneratedContent.match(/\{[^{}]*"prompts"\s*:\s*\[[\s\S]*?\]\s*\}/); 
    if (jsonObjMatch) {
      debugInfo.parseMethod = 'directJson';
      const parsed = safeJsonParse(jsonObjMatch[0]);
      if (parsed && parsed.prompts && Array.isArray(parsed.prompts)) {
        for (let i = 0; i < parsed.prompts.length && i < 8; i++) {
          const item = parsed.prompts[i];
          const promptText = item.prompt || item.text || item.content || item.description || '';
          if (promptText && promptText.length > 20 && !prompts[i]) {
            prompts[i] = promptText;
          }
        }
        debugInfo.parsedCount = prompts.filter(p => p).length;
      }
    }
  } catch (e) {
    debugInfo.parseError = 'directJson: ' + (e.message || '');
  }
}

// ============ 方法3: 逐个提取prompt字段 ============
if (prompts.filter(p => p).length < 4) {
  try {
    const promptFieldPattern = /"prompt"\s*:\s*"([^"]{30,})"/g;
    let match;
    let idx = 0;
    while ((match = promptFieldPattern.exec(aiGeneratedContent)) !== null && idx < 8) {
      if (match[1] && match[1].length > 20 && !prompts[idx]) {
        prompts[idx] = match[1];
        idx++;
      }
    }
    if (idx > 0) {
      debugInfo.parseMethod = 'promptField';
      debugInfo.parsedCount = prompts.filter(p => p).length;
    }
  } catch (e) {
    debugInfo.parseError = 'promptField: ' + (e.message || '');
  }
}

// ============ 方法4: 正则提取【主图N】格式 ============
if (prompts.filter(p => p).length < 4) {
  try {
    const promptPattern = /【主图(\d+)】[\s\S]*?提示词[：:.]\s*([^【]+)/g;
    let match;
    while ((match = promptPattern.exec(aiGeneratedContent)) !== null) {
      const index = parseInt(match[1]) - 1;
      let prompt = match[2].trim();
      prompt = prompt.replace(/```[\s\S]*?```/g, '').trim();
      prompt = prompt.replace(/^[提示词prompt][：:\s]+/i, '').trim();
      prompt = prompt.split(/---|===|【主图/)[0].trim();
      if (prompt && prompt.length > 20 && index >= 0 && index < 8 && !prompts[index]) {
        prompts[index] = prompt;
      }
    }
    if (prompts.filter(p => p).length >= 4) {
      debugInfo.parseMethod = 'chinesePattern';
      debugInfo.parsedCount = prompts.filter(p => p).length;
    }
  } catch (e) {
    debugInfo.parseError = 'chinesePattern: ' + (e.message || '');
  }
}

// ============ 方法5: 提取英文提示词部分 ============
if (prompts.filter(p => p).length < 4) {
  try {
    const englishPromptPattern = /(?:prompt|English|Complete)[\s：:]+\s*['"]?([A-Za-z][^\u3010\u3011]{50,}?)(?=['"]?\s*[,}\n]|【|$)/gi;
    let englishMatch;
    let idx = 0;
    while ((englishMatch = englishPromptPattern.exec(aiGeneratedContent)) !== null && idx < 8) {
      const promptText = englishMatch[1].trim();
      if (promptText.length > 30 && !prompts[idx]) {
        prompts[idx] = promptText;
        idx++;
      }
    }
    if (idx > 0) {
      debugInfo.parseMethod = 'englishPrompt';
      debugInfo.parsedCount = prompts.filter(p => p).length;
    }
  } catch (e) {}
}

// ============ 方法6: 提取所有英文长句 ============
if (prompts.filter(p => p).length < 4) {
  try {
    const allEnglish = aiGeneratedContent.match(/[A-Z][a-zA-Z\s,.'"\-()]+(?:product|image|photo|scene|background|lighting|white|studio|professional)[^\u3010\u3011\n]{40,}/gi);
    if (allEnglish && allEnglish.length > 0) {
      const uniquePrompts = [...new Set(allEnglish.map(p => p.trim()))];
      for (let i = 0; i < Math.min(8, uniquePrompts.length); i++) {
        if (!prompts[i] && uniquePrompts[i].length > 30) {
          prompts[i] = uniquePrompts[i];
        }
      }
      debugInfo.parseMethod = 'englishLongSentence';
      debugInfo.parsedCount = prompts.filter(p => p).length;
    }
  } catch (e) {}
}

// ============ 处理解析结果 ============
const validPrompts = prompts.filter(p => p && p.length > 20);
const uniqueValidPrompts = [...new Set(validPrompts)];

// 【修复】统一语言的降级提示词 - 增加产品参考要求
const fallbackPrompts = isChinesePrompt ? [
  '【必须严格参考产品原图】纯白背景 RGB 255 255 255，产品外观必须与参考图完全一致，只展示单个产品，产品为绝对主角居中，占画面85%，无文字，商品写实摄影，无变形，无失真，准确比例，影棚灯光，8K高清',
  '【必须严格参考产品原图】产品外观与参考图一致，生活场景中展示，自然光线，产品为主角居中，完整展示产品，商品写实摄影，无变形，准确比例，8K高清',
  '【必须严格参考产品原图】产品细节与参考图一致，细节特写，近距离视角，产品为主角，焦点对准材质纹理，商品写实摄影，无变形，专业产品摄影',
  '【必须严格参考产品原图】产品外观与参考图完全一致，卖点展示，产品居中为主角，专业影棚灯光，完整展示产品，无变形，商业质量，8K高清',
  '【必须严格参考产品原图】产品与参考图一模一样，使用场景展示，产品为主角突出展示，自然场景，商品写实摄影，准确比例，无变形，专业摄影',
  '【必须严格参考产品原图】产品外观颜色材质与参考图一致，品质展示，高端呈现，产品为绝对主角，专业光线，完整展示产品，无变形，8K高清',
  '【必须严格参考产品原图】产品形状与参考图完全一致，多角度展示，3/4角度视角，产品为主角居中，完整展示产品，商品写实摄影，无变形，影棚质量',
  '【必须严格参考产品原图】产品尺寸外观与参考图一致，尺寸参考，产品为主角带比例参照，完整展示产品，商品写实摄影，准确比例，无变形，专业商业'
] : [
  '[MUST MATCH REFERENCE IMAGES] pure white background RGB 255 255 255, product appearance MUST be EXACTLY identical to reference images, ONLY ONE SINGLE PRODUCT, product as absolute hero centered, 85% frame coverage, no text, photorealistic, no distortion, accurate proportions, studio lighting, high resolution 8K',
  '[MUST MATCH REFERENCE IMAGES] product appearance identical to reference, lifestyle scene, natural lighting, product as hero centered, complete product display, photorealistic, no distortion, accurate proportions, high resolution',
  '[MUST MATCH REFERENCE IMAGES] product details matching reference, detail shot, close-up view, product as hero, sharp focus on texture and material, photorealistic, no distortion, professional product photography',
  '[MUST MATCH REFERENCE IMAGES] product EXACTLY like reference images, feature highlight, product centered as hero, professional studio lighting, complete product display, no distortion, commercial quality, 8K resolution',
  '[MUST MATCH REFERENCE IMAGES] product identical to reference, in use demonstration, product as hero prominently displayed, natural setting, photorealistic, accurate proportions, no distortion, professional photography',
  '[MUST MATCH REFERENCE IMAGES] product color and material matching reference, quality showcase, premium presentation, product as absolute hero, professional lighting, complete product visible, no distortion, high resolution',
  '[MUST MATCH REFERENCE IMAGES] product shape EXACTLY like reference, multi-angle view, 3/4 angle perspective, product as hero centered, complete product display, photorealistic, no distortion, studio quality',
  '[MUST MATCH REFERENCE IMAGES] product size and appearance matching reference, size reference, product as hero with scale comparison, complete product visible, photorealistic, accurate proportions, no distortion, professional commercial'
];

if (uniqueValidPrompts.length > 0) {
  for (let i = 0; i < 8; i++) {
    if (!prompts[i] || prompts[i].length < 20) {
      prompts[i] = uniqueValidPrompts[i % uniqueValidPrompts.length];
    }
  }
} else {
  debugInfo.parseMethod = 'fallback';
  for (let i = 0; i < 8; i++) {
    prompts[i] = fallbackPrompts[i];
  }
}

// ============ 构建批量请求 ============
const generationData = [];

// 【关键修改】构建callbackUrl，将$execution.resumeUrl中的host:port替换为配置的地址
let rawResumeUrl = $execution.resumeUrl || `${N8N_BASE_URL}/webhook/image-callback/${requestId}`;
const callbackUrl = rawResumeUrl.replace(/^(https?:\/\/)[^\/]+/, `$1${N8N_HOST}`);

const sharedImageUrls = imgUrls && imgUrls.length > 0 ? imgUrls : [];

// 【修复】检测提示词语言的函数
function isChineseText(text) {
  return /[\u4e00-\u9fa5]/.test(text);
}

// 【新增】记录每个最终prompt的调试信息
const debugFinalPrompts = [];

try {
  for (let i = 0; i < 8; i++) {
    // 【关键】每次循环都从prompts数组获取对应索引的值
    const originalPrompt = prompts[i];
    let prompt = originalPrompt || (isChinesePrompt ? '产品图片，商品写实摄影，商业摄影' : 'product image, photorealistic, commercial photography');

    // 检测原始提示词语言
    const promptIsChinese = isChineseText(prompt);

    // ============ 【关键增强】为每张图片添加产品参考要求 ============
    if (hasProductImages) {
      // 检查提示词是否已经包含参考要求
      const hasReferenceKeyword = promptIsChinese 
        ? (prompt.includes('参考') || prompt.includes('原图') || prompt.includes('一致'))
        : (prompt.toLowerCase().includes('reference') || prompt.toLowerCase().includes('match') || prompt.toLowerCase().includes('identical'));

      if (!hasReferenceKeyword) {
        // 在提示词开头添加强制产品参考要求
        prompt = PRODUCT_REFERENCE_REQUIREMENTS.prefix + prompt + PRODUCT_REFERENCE_REQUIREMENTS.suffix;
      }
    }

    // ============ 【关键】第一张图片强制使用亚马逊主图要求（只展示单个产品） ============
    // 【优化】第一张白底主图不添加无关元数据，保持简洁专业
    if (i === 0) {
      // 提取产品描述部分（去掉原有的背景、文字等描述）
      let productDescription = prompt;

      // 尝试提取产品主体描述
      if (promptIsChinese) {
        // 移除背景相关描述和多产品相关描述
        productDescription = productDescription
          .replace(/纯白[色]?背景[^，。]*/g, '')
          .replace(/白[色]?背景[^，。]*/g, '')
          .replace(/RGB[^，。]*/gi, '')
          .replace(/无文字[^，。]*/g, '')
          .replace(/禁止[^，。]*/g, '')
          .replace(/多个产品[^，。]*/g, '')
          .replace(/产品组合[^，。]*/g, '')
          .replace(/参考权重[^，。]*/g, '')
          .replace(/产品图数量[^，。]*/g, '')
          .replace(/[，。]+/g, '，')
          .replace(/^[，。]+|[，。]+$/g, '')
          .trim();

        // 使用中文亚马逊主图要求重新构建，强制只展示单个产品
        // 【关键】第一张白底主图只需要产品参考要求，不需要额外元数据
        const referencePrefix = hasProductImages ? PRODUCT_REFERENCE_REQUIREMENTS.prefix : '';
        const referenceSuffix = hasProductImages ? PRODUCT_REFERENCE_REQUIREMENTS.suffix : '';
        prompt = referencePrefix + AMAZON_MAIN_IMAGE_REQUIREMENTS.prefix + productDescription + AMAZON_MAIN_IMAGE_REQUIREMENTS.suffix + referenceSuffix;
      } else {
        // 移除英文背景相关描述和多产品相关描述
        productDescription = productDescription
          .replace(/pure white background[^,.]*/gi, '')
          .replace(/white background[^,.]*/gi, '')
          .replace(/RGB[^,.]*/gi, '')
          .replace(/no text[^,.]*/gi, '')
          .replace(/multiple products?[^,.]*/gi, '')
          .replace(/product combinations?[^,.]*/gi, '')
          .replace(/reference weight[^,.]*/gi, '')
          .replace(/product images count[^,.]*/gi, '')
          .replace(/,\s*,/g, ',')
          .replace(/^[,\s]+|[,\s]+$/g, '')
          .trim();

        // 使用英文亚马逊主图要求重新构建，强制只展示单个产品
        // 【关键】第一张白底主图只需要产品参考要求，不需要额外元数据
        const referencePrefix = hasProductImages ? PRODUCT_REFERENCE_REQUIREMENTS.prefix : '';
        const referenceSuffix = hasProductImages ? PRODUCT_REFERENCE_REQUIREMENTS.suffix : '';
        prompt = referencePrefix + AMAZON_MAIN_IMAGE_REQUIREMENTS.prefix + productDescription + AMAZON_MAIN_IMAGE_REQUIREMENTS.suffix + referenceSuffix;
      }
    }

    // 清理提示词 - 保留中文字符和Unicode字符
    const cleanPrompt = prompt
      .replace(/"/g, "'")  // 双引号转单引号
      .replace(/\n/g, " ") // 换行转空格
      .replace(/\r/g, " ") // 回车转空格
      .replace(/\s+/g, " ") // 多个空格合并
      .replace(/[\x00-\x1F\x7F]/g, '') // 只移除控制字符
      .trim();

    // 【调试】记录每个prompt的信息
    debugFinalPrompts.push({
      index: i + 1,
      isMainImage: i === 0,
      hasProductReference: hasProductImages,
      originalLength: originalPrompt ? originalPrompt.length : 0,
      finalLength: cleanPrompt.length,
      preview: cleanPrompt.substring(0, 150) + '...'
    });

    const imageParams = {
      unique_key: `image_${i + 1}_${requestId}`,
      size: i === 0 ? "1:1" : "2:3",  // 第一张主图使用1:1比例
      prompt: cleanPrompt,
      image_urls: sharedImageUrls  // 传递产品图片作为参考
    };

    generationData.push(imageParams);
  }

  const batchRequest = {
    workflow_type: "image.batch.generate",
    inputs: {
      model_id: modelId,
      generation_data: generationData,
      callback_url: callbackUrl,
      source: "material_center::ai_image"
    }
  };

  // 【调试】检查generationData中的prompt是否都不同
  const uniqueFinalPrompts = new Set(generationData.map(d => d.prompt));
  debugInfo.finalUniqueCount = uniqueFinalPrompts.size;

  return [{
    json: {
      request_body: batchRequest,
      request_id: requestId,
      callback_url: callbackUrl,
      image_count: 8,
      product_image_urls: sharedImageUrls,
      debug_info: debugInfo,
      debug_parsed_prompts: prompts.map((p, i) => ({
        index: i + 1,
        length: p ? p.length : 0,
        preview: p ? p.substring(0, 100) + '...' : 'empty'
      })),
      debug_final_prompts: debugFinalPrompts,
      debug_unique_count: new Set(prompts.filter(p => p && p.length > 20)).size
    }
  }];

} catch (error) {
  return [{
    json: {
      request_body: {},
      request_id: requestId,
      callback_url: callbackUrl,
      image_count: 0,
      error: error.message || 'Unknown error',
      debug_info: debugInfo
    }
  }];
}

