// ============ 辅助函数 ============
function safeJsonParse(content) {
  if (!content || typeof content !== 'string') return null;
  try {
    return JSON.parse(content);
  } catch(e) {
    try {
      const jsonMatch = content.match(/```json\s*([\s\S]*?)```/);
      if (jsonMatch && jsonMatch[1]) return JSON.parse(jsonMatch[1].trim());
      const directMatch = content.match(/\{[\s\S]*\}/);
      if (directMatch && directMatch[0]) return JSON.parse(directMatch[0]);
    } catch(e2) {
      // 解析失败，返回null
    }
  }
  return null;
}

function safeGetNodeData(nodeName) {
  try {
    const nodeData = $(nodeName);
    if (nodeData && typeof nodeData.first === 'function') {
      const first = nodeData.first();
      if (first && first.json) {
        return first.json;
      }
    }
  } catch(e) {
    // 节点数据获取失败
  }
  return {};
}

// 【修复】兼容openapi.giikin.com API格式: {code:0, data:"内容", message:"ok"}
function extractApiContent(nodeName) {
  try {
    const result = safeGetNodeData(nodeName);

    // 【最优先】openapi.giikin.com 格式: data直接是字符串内容
    if (result.data !== undefined) {
      if (typeof result.data === 'string') {
        return result.data;
      }
      // data是对象的情况
      if (result.data && typeof result.data === 'object') {
        if (result.data.content) return result.data.content;
        if (result.data.message && typeof result.data.message === 'string') return result.data.message;
        if (result.data.text) return result.data.text;
      }
    }

    // 方式2：标准OpenAI格式 choices[0].message.content
    if (result.choices && Array.isArray(result.choices) && result.choices[0]) {
      if (result.choices[0].message && result.choices[0].message.content) {
        return result.choices[0].message.content;
      }
      if (result.choices[0].content) {
        return result.choices[0].content;
      }
    }

    // 方式3：直接content/result/message字段
    if (result.content) return typeof result.content === 'string' ? result.content : JSON.stringify(result.content);
    if (result.result && typeof result.result === 'string') return result.result;
    if (result.message && typeof result.message === 'string' && result.message !== 'ok') return result.message;
    if (result.output) {
      if (typeof result.output === 'string') return result.output;
      if (result.output.content) return result.output.content;
      if (result.output.text) return result.output.text;
    }
    if (result.text) return result.text;
    if (result.response) {
      if (typeof result.response === 'string') return result.response;
      if (result.response.content) return result.response.content;
    }

  } catch(e) {
    // 提取失败
  }
  return '';
}

// ============ 主逻辑 ============
try {
