  const imageAnalysisRaw = extractApiContent('图片识别与提示词反推');

  // 获取竞品分析结果
  const competitorInfoRaw = extractApiContent('竞品信息解析');

  // 获取Listing文案
  const listingRaw = extractApiContent('Listing文案生成');
  let listingData = safeJsonParse(listingRaw) || {};

  // 【调试】记录提取到的原始内容长度
  const debugExtraction = {
    imageAnalysisLength: imageAnalysisRaw.length,
    competitorInfoLength: competitorInfoRaw.length,
    listingRawLength: listingRaw.length,
    listingRawPreview: listingRaw.substring(0, 500)
  };

  // 如果解析失败，尝试正则提取
  if (!listingData.title && listingRaw) {
    try {
      const titleMatch = listingRaw.match(/\"title\"\s*:\s*\"([^\"]+)\"/);
      const descMatch = listingRaw.match(/\"description\"\s*:\s*\"([^\"]+)\"/);
      const searchMatch = listingRaw.match(/\"search_keywords\"\s*:\s*\"([^\"]+)\"/);
      const backendMatch = listingRaw.match(/\"backend_keywords\"\s*:\s*\"([^\"]+)\"/);

      if (titleMatch && titleMatch[1]) listingData.title = titleMatch[1];
      if (descMatch && descMatch[1]) listingData.description = descMatch[1];
      if (searchMatch && searchMatch[1]) listingData.search_keywords = searchMatch[1];
      if (backendMatch && backendMatch[1]) listingData.backend_keywords = backendMatch[1];

      const bulletMatch = listingRaw.match(/\"bullet_points\"\s*:\s*\[([\s\S]*?)\]/);
      if (bulletMatch && bulletMatch[1]) {
        const bullets = bulletMatch[1].match(/\"([^\"]+)\"/g);
        if (bullets && Array.isArray(bullets)) {
          listingData.bullet_points = bullets.map(b => b.replace(/\"/g, ''));
        }
      }
    } catch(e) {
      // 正则提取失败
    }
  }

  // 获取做图提示词
  const imagePrompts = extractApiContent('做图提示词生成');

  // 获取A+内容
  const aplusContent = extractApiContent('A+提示词生成');

  // 质量检查
  const titleStr = listingData.title || '';
  const bulletPoints = listingData.bullet_points || [];
  const descriptionStr = listingData.description || '';

  // 【修复】has_image_prompts检测逻辑
  const hasImagePrompts = (imagePrompts.includes('"prompts"') && imagePrompts.includes('"prompt"')) || 
                          (imagePrompts.includes('"image_number"') && imagePrompts.includes('"prompt"')) ||
                          (imagePrompts.length > 500);

  // has_aplus_prompts检测
  const hasAplusPrompts = aplusContent.includes('【模块') || aplusContent.includes('Module') || aplusContent.length > 200;

  const qualityChecks = {
    has_title: titleStr.length > 10,
    title_length_ok: titleStr.length > 0 && titleStr.length <= 200,
    has_bullets: Array.isArray(bulletPoints) && bulletPoints.length >= 5,
    has_description: descriptionStr.length > 50,
    has_image_prompts: hasImagePrompts,
    has_aplus_prompts: hasAplusPrompts,
    has_generated_images: generatedImages.length > 0
  };

  const passedChecks = Object.values(qualityChecks).filter(v => v === true).length;
  const totalChecks = Object.keys(qualityChecks).length;
  const qualityScore = totalChecks > 0 ? Math.round(passedChecks / totalChecks * 100) : 0;

  // 安全获取图片URL列表
  const productImgList = inputData.product_img_url_list || [];
  const competitorImgList = inputData.competitor_img_url_list || [];

  let productImgUrlList = [];
  if (Array.isArray(productImgList)) {
    productImgUrlList = productImgList.filter(url => url && typeof url === 'string' && url.trim().length > 0);
  } else if (typeof productImgList === 'string') {
    productImgUrlList = productImgList.split(/[,，\n]+/).map(u => u.trim()).filter(u => u);
  }

  let competitorImgUrlList = [];
  if (Array.isArray(competitorImgList)) {
    competitorImgUrlList = competitorImgList.filter(url => url && typeof url === 'string' && url.trim().length > 0);
  } else if (typeof competitorImgList === 'string') {
    competitorImgUrlList = competitorImgList.split(/[,，\n]+/).map(u => u.trim()).filter(u => u);
  }

  const productImageCount = productImgUrlList.length;
  const competitorImageCount = competitorImgUrlList.length;

  // 构建结果
  const result = {
    request_id: requestId,
    meta: {
      generated_at: new Date().toISOString(),
      quality_score: qualityScore,
      quality_checks: qualityChecks,
      workflow_version: "v5-batch-async",
      debug_extraction: debugExtraction
    },
    input: {
      country: inputData.country || 'jp',
      keywords: inputData.keywords || '',
      title: productTitle,
      asin_link: inputData.asin_link || '',
      product_specs: inputData.product_specs || '',
      prompt_lang: inputData.prompt_lang || 'en',
      product_image_count: productImageCount,
      competitor_image_count: competitorImageCount,
      product_img_url_list: productImgUrlList,
      competitor_img_url_list: competitorImgUrlList
    },
    listing: {
      title: titleStr,
      title_length: titleStr.length,
      bullet_points: bulletPoints,
      description: descriptionStr,
      description_length: descriptionStr.length,
      search_keywords: listingData.search_keywords || '',
      backend_keywords: listingData.backend_keywords || ''
    },
    image_prompts: imagePrompts,
    aplus_prompts: aplusContent,
    generated_images: generatedImages,
    _raw: {
      image_analysis: imageAnalysisRaw.substring(0, 5000),
      competitor_info: competitorInfoRaw.substring(0, 5000),
      listing_raw: listingRaw.substring(0, 5000)
    }
  };

  return [{ 
    json: { 
      result_json: result, 
      callback_url: inputData.callback_url || '',
      success: qualityScore > 90,
      request_id: requestId
    } 
  }];

} catch (error) {
  return [{ 
    json: { 
      result_json: {
        request_id: 'error',
        error: error.message || 'Unknown error',
        meta: {
          generated_at: new Date().toISOString(),
