function extractCompetitorAttackData(competitorInfo) {
  const result = { negatives: [], improvements: [], attackNotes: '' };
  try {
    const jsonMatch = competitorInfo.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      if (parsed.negative_reviews) {
        const neg = parsed.negative_reviews;
        result.negatives = typeof neg === 'object' && neg.details ? neg.details : (Array.isArray(neg) ? neg : []);
      }
      if (parsed.improvement_opportunities) {
        result.improvements = Array.isArray(parsed.improvement_opportunities) 
          ? parsed.improvement_opportunities : [parsed.improvement_opportunities];
      }
    }
  } catch(e) {}

  if (result.negatives.length > 0 || result.improvements.length > 0) {
    let attackList = [];
    const allNeg = result.negatives.join(' ') + ' ' + result.improvements.join(' ');
    const strategies = {
      '质量差': { scene: '耐用性测试场景', ad: '高品质' },
      '做工粗糙': { scene: '细节特写', ad: '精工细作' },
      '材质差': { scene: '材质展示', ad: '优质材质' },
      '不耐用': { scene: '长期使用展示', ad: '经久耐用' },
      '操作复杂': { scene: '简易操作展示', ad: '一键操作' },
      '包装简陋': { scene: '精美包装展示', ad: '送礼佳选' },
      '尺寸不合适': { scene: '人体工学展示', ad: '完美贴合' },
      '噪音大': { scene: '静音环境展示', ad: '静音设计' },
      '不稳定': { scene: '稳定性展示', ad: '稳固可靠' },
      '功能少': { scene: '多功能展示', ad: '多功能' }
    };
    for (const [weak, strat] of Object.entries(strategies)) {
      if (allNeg.includes(weak)) attackList.push(`- 竞品被抱怨"${weak}" → 场景突出${strat.scene}，广告词使用"${strat.ad}"`);
    }
    result.attackNotes = attackList.join('\n');
  }
  return result;
}

