    // 【最优先】openapi.giikin.com 格式: data直接是字符串内容
    if (result.data !== undefined) {
      if (typeof result.data === 'string') return result.data;
      if (result.data && typeof result.data === 'object') {
        if (result.data.content) return result.data.content;
        if (result.data.message && typeof result.data.message === 'string') return result.data.message;
      }
    }

    // 标准OpenAI格式
    if (result.choices && Array.isArray(result.choices) && result.choices[0]) {
      if (result.choices[0].message && result.choices[0].message.content) {
        return result.choices[0].message.content;
      }
    }

    // 其他格式
    if (result.content) return typeof result.content === 'string' ? result.content : JSON.stringify(result.content);
    if (result.result && typeof result.result === 'string') return result.result;
    if (result.text) return result.text;

  } catch(e) {}
  return '';
}

function extractCompetitorAttackStrategies(competitorInfo) {
  const result = {
    negativePoints: [],
    improvementOpportunities: [],
    attackStrategies: []
  };

  try {
    const jsonMatch = competitorInfo.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);

      if (parsed.negative_reviews) {
        if (typeof parsed.negative_reviews === 'object' && parsed.negative_reviews.details) {
          result.negativePoints = parsed.negative_reviews.details;
        } else if (Array.isArray(parsed.negative_reviews)) {
          result.negativePoints = parsed.negative_reviews;
        }
      }

      if (parsed.improvement_opportunities) {
        result.improvementOpportunities = Array.isArray(parsed.improvement_opportunities) 
          ? parsed.improvement_opportunities 
          : [parsed.improvement_opportunities];
      }
    }
  } catch(e) {}

  const weaknessToStrategy = {
    '质量差': { scene: '耐用性展示', adCN: '高品质/经久耐用', adEN: 'Premium Quality / Long-lasting', moduleType: '品质展示模块' },
    '做工粗糙': { scene: '细节特写', adCN: '精工细作/匠心品质', adEN: 'Exquisite Craftsmanship', moduleType: '工艺展示模块' },
    '材质差': { scene: '材质展示', adCN: '优质材质/环保安全', adEN: 'Premium Material / Eco-Safe', moduleType: '材质展示模块' },
    '不耐用': { scene: '长期使用展示', adCN: '持久耐用/品质保证', adEN: 'Durable / Quality Guaranteed', moduleType: '耐用性展示模块' },
    '操作复杂': { scene: '简易操作展示', adCN: '一键操作/简单易用', adEN: 'One-Click / Easy to Use', moduleType: '易用性展示模块' },
    '包装简陋': { scene: '精美包装展示', adCN: '精美包装/送礼佳选', adEN: 'Premium Packaging / Gift Ready', moduleType: '包装展示模块' },
    '尺寸不合适': { scene: '人体工学展示', adCN: '完美贴合/人体工学', adEN: 'Perfect Fit / Ergonomic Design', moduleType: '设计展示模块' },
    '噪音大': { scene: '静谧环境展示', adCN: '静音设计/安静享受', adEN: 'Silent Design / Quiet Enjoyment', moduleType: '静音展示模块' },
    '不稳定': { scene: '稳定性展示', adCN: '稳固可靠/防滑设计', adEN: 'Rock-Solid / Anti-Slip Design', moduleType: '稳定性展示模块' },
    '功能少': { scene: '多功能展示', adCN: '多功能/一机多用', adEN: 'Multi-Function / Versatile', moduleType: '多功能展示模块' }
  };

  const allNegatives = [...result.negativePoints, ...result.improvementOpportunities].join(' ');
  for (const [weakness, strategy] of Object.entries(weaknessToStrategy)) {
    if (allNegatives.includes(weakness) || allNegatives.toLowerCase().includes(weakness.toLowerCase())) {
      result.attackStrategies.push({ weakness, ...strategy });
    }
  }

  return result;
}

