// 获取request_id（从主流程的"设置输入变量"节点获取，因为是在同一执行中）
let requestId = '';
try {
  const inputVars = $('设置输入变量').first().json || {};
  requestId = inputVars.request_id || $execution.id;
} catch(e) {
  requestId = $execution.id;
}

// 提取工作流信息
const workflowId = callbackData.workflow_id;
const runId = callbackData.run_id;
const workflowType = callbackData.workflow_type;

// 从result.generation_data中提取所有图片（兼容可能的data字段）
const generationData = callbackData.result?.generation_data || callbackData.data?.generation_data || [];
const generatedImages = [];

// 遍历所有生成结果，提取图片URL
for (const item of generationData) {
  const uniqueKey = item.unique_key;
  const imageUrls = item.generated_image_urls || [];

  // 从unique_key中提取图片索引（格式：image_1_requestId）
  const keyMatch = uniqueKey.match(/image_(\d+)_/);
  const imageIndex = keyMatch ? parseInt(keyMatch[1]) : null;

  // 每项可能有多张图片（generated_image_urls是数组）
  for (let i = 0; i < imageUrls.length; i++) {
    generatedImages.push({
      unique_key: uniqueKey,
      image_index: imageIndex || (generatedImages.length + 1),
      image_url: imageUrls[i],
      size: item.size,
      prompt: item.prompt
    });
  }
}

// 按image_index排序
generatedImages.sort((a, b) => (a.image_index || 0) - (b.image_index || 0));

